async (params, browser) => {
  // Open Untappd
  await browser.open(`https://untappd.com/w/brewery/${params.brewery_id}`)

  // Wait for page
  await browser.waitForSelector('h1, .name, .content', 15000)

  // Let page render
  await browser.wait(2500)

  // Extract data
  const result = await browser.evaluate(`const name = document.querySelector('h1, .name h1')?.textContent?.trim() || ''; const loc = document.querySelector('.brewery-location, .location')?.textContent?.trim() || ''; const beers = []; document.querySelectorAll('.beer-item, .beer-list .beer').forEach((el, i) => { if (i < 10) beers.push(el.querySelector('.name a, .beer-name')?.textContent?.trim() || ''); }); return { name, location: loc, beers, url: window.location.href };`)

  return result
}
